html:
{# Work Order Contract — professional print format.
   Layout: Page 1 = contract summary, Page 2 = terms & signatures,
   Annexure 1 (page 3+) = detailed BOQ. Designed for A4 portrait. #}

<style>
  /* Scope all styles to this print to avoid bleed into Frappe's UI */
  .wo-print {
    font-family: "Inter", "Helvetica Neue", Helvetica, Arial, sans-serif;
    color: #1a1a1a;
    line-height: 1.4;
    font-size: 10.5pt;
  }
  .wo-print h1, .wo-print h2, .wo-print h3, .wo-print h4 {
    margin: 0;
    color: #000;
    font-weight: 600;
  }
  .wo-print h1 { font-size: 18pt; letter-spacing: 0.5pt; }
  .wo-print h2 { font-size: 13pt; margin: 18px 0 8px; padding-bottom: 4px; border-bottom: 1.5px solid #000; }
  .wo-print h3 { font-size: 11pt; margin: 14px 0 6px; color: #333; }
  .wo-print h4 { font-size: 10pt; margin: 0 0 4px; }
  .wo-print p  { margin: 4px 0; }
  .wo-print .muted { color: #666; font-size: 9pt; }

  .wo-print table.kv { width: 100%; border-collapse: collapse; margin: 8px 0; }
  .wo-print table.kv td { padding: 4px 8px; vertical-align: top; border-bottom: 1px solid #eee; }
  .wo-print table.kv td.label { font-weight: 600; width: 30%; color: #333; }
  .wo-print table.kv td.value { width: 70%; }

  .wo-print table.parties { width: 100%; border-collapse: collapse; margin: 10px 0; border: 1px solid #ddd; }
  .wo-print table.parties td { padding: 10px 12px; vertical-align: top; width: 50%; }
  .wo-print table.parties td + td { border-left: 1px solid #ddd; }

  .wo-print table.data { width: 100%; border-collapse: collapse; margin: 8px 0; }
  .wo-print table.data th, .wo-print table.data td { padding: 6px 8px; border: 1px solid #999; text-align: left; vertical-align: top; font-size: 10pt; }
  .wo-print table.data th { background: #f2f2f2; font-weight: 600; }
  .wo-print table.data td.amt, .wo-print table.data th.amt { text-align: right; white-space: nowrap; }
  .wo-print table.data .head-row td { background: #fafafa; font-weight: 600; }
  .wo-print table.data .head-subtotal td { background: #f7f7f7; font-style: italic; }
  .wo-print table.data .grand-total td { background: #000; color: #fff; font-weight: 700; font-size: 11pt; padding: 8px; }
  .wo-print table.data .total-row td { font-weight: 700; background: #ececec; }

  .wo-print .title-bar { text-align: center; margin: 0 0 14px; border-bottom: 2px solid #000; padding-bottom: 8px; }
  .wo-print .title-bar .doc-no { font-size: 11pt; font-weight: 600; letter-spacing: 0.3pt; }
  .wo-print .status-pill {
    display: inline-block; padding: 2px 10px; border-radius: 3px; font-size: 9pt; font-weight: 600;
    text-transform: uppercase; letter-spacing: 0.5pt; vertical-align: middle; margin-left: 6px;
  }
  .wo-print .status-draft { background: #fff4e5; color: #b75c00; border: 1px solid #d99240; }
  .wo-print .status-submitted { background: #e3f1e6; color: #1e6b32; border: 1px solid #2e8b48; }
  .wo-print .status-cancelled { background: #fbe5e5; color: #a91414; border: 1px solid #c8302e; }
  .wo-print .status-amended { background: #e7eef9; color: #154a98; border: 1px solid #2f6db9; }

  .wo-print .amount-in-words { margin: 10px 0; padding: 8px 12px; background: #f7f7f7; border-left: 4px solid #333; font-style: italic; }
  .wo-print .annexure-note { margin: 14px 0; padding: 8px 12px; border: 1px dashed #888; font-size: 9.5pt; color: #444; }

  .wo-print .sig-block { margin-top: 36px; }
  .wo-print .sig-block table { width: 100%; border-collapse: collapse; }
  .wo-print .sig-block td { width: 50%; padding: 0 14px; vertical-align: top; }
  .wo-print .sig-line { border-top: 1px solid #333; margin: 50px 0 6px; }
  .wo-print .scope-detail { padding: 8px 0; font-size: 10pt; }
  .wo-print .scope-detail p { margin: 4px 0; }

  /* Page break behavior */
  .wo-print .page-break { page-break-after: always; break-after: page; }
  .wo-print table { page-break-inside: auto; }
  .wo-print tr    { page-break-inside: avoid; page-break-after: auto; }
  .wo-print thead { display: table-header-group; }
  .wo-print tfoot { display: table-footer-group; }

  /* Footer print rule */
  .wo-print .footer-note { margin-top: 24px; font-size: 9pt; color: #666; text-align: center; border-top: 1px solid #ccc; padding-top: 6px; }
</style>

{# ===================== Helpers ===================== #}
{%- set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "INR" -%}
{%- macro money(amt) -%}
  {{ frappe.utils.fmt_money(amt or 0, currency=company_currency) }}
{%- endmacro -%}
{%- macro show_date(d) -%}
  {%- if d -%}{{ frappe.utils.formatdate(d, "dd MMM yyyy") }}{%- else -%}—{%- endif -%}
{%- endmacro -%}
{%- macro show_pct(v) -%}
  {%- if v is none -%}—{%- else -%}{{ "%.2f"|format(v|float) }}%{%- endif -%}
{%- endmacro -%}
{%- macro status_pill() -%}
  {%- if doc.amended_from -%}
    <span class="status-pill status-amended">Amended from {{ doc.amended_from }}</span>
  {%- elif doc.docstatus == 0 -%}
    <span class="status-pill status-draft">Draft</span>
  {%- elif doc.docstatus == 1 -%}
    <span class="status-pill status-submitted">Submitted</span>
  {%- elif doc.docstatus == 2 -%}
    <span class="status-pill status-cancelled">Cancelled</span>
  {%- endif -%}
{%- endmacro -%}

<div class="wo-print">

{# ================================================== #}
{# PAGE 1 — CONTRACT SUMMARY                          #}
{# ================================================== #}

<div class="title-bar">
  <h1>WORK ORDER</h1>
  <div class="doc-no">
    {{ doc.name }} &nbsp;|&nbsp; Dated {{ show_date(doc.wo_date) }} {{ status_pill() }}
  </div>
</div>

<table class="parties">
  <tr>
    <td>
      <h4>FROM (Employer)</h4>
      <p><strong>{{ doc.company }}</strong></p>
      {%- set caddr = frappe.db.get_value("Address",
            {"link_doctype": "Company", "link_name": doc.company, "is_primary_address": 1},
            ["address_line1", "address_line2", "city", "state", "pincode", "country", "gstin"],
            as_dict=True) -%}
      {%- if caddr -%}
        <p>
          {{ caddr.address_line1 or "" }}{% if caddr.address_line2 %}, {{ caddr.address_line2 }}{% endif %}<br>
          {{ caddr.city or "" }}{% if caddr.state %}, {{ caddr.state }}{% endif %}{% if caddr.pincode %} - {{ caddr.pincode }}{% endif %}<br>
          {{ caddr.country or "" }}
        </p>
        {%- if caddr.gstin -%}<p class="muted">GSTIN: {{ caddr.gstin }}</p>{%- endif -%}
      {%- endif -%}
    </td>
    <td>
      <h4>TO (Contractor)</h4>
      <p><strong>{{ doc.supplier_name or doc.supplier }}</strong></p>
      {%- set saddr = frappe.db.get_value("Address",
            {"link_doctype": "Supplier", "link_name": doc.supplier, "is_primary_address": 1},
            ["address_line1", "address_line2", "city", "state", "pincode", "gstin"],
            as_dict=True) -%}
      {%- if saddr -%}
        <p>
          {{ saddr.address_line1 or "" }}{% if saddr.address_line2 %}, {{ saddr.address_line2 }}{% endif %}<br>
          {{ saddr.city or "" }}{% if saddr.state %}, {{ saddr.state }}{% endif %}{% if saddr.pincode %} - {{ saddr.pincode }}{% endif %}
        </p>
        {%- if saddr.gstin -%}<p class="muted">GSTIN: {{ saddr.gstin }}</p>{%- endif -%}
      {%- endif -%}
      {%- set sgstin_no = frappe.db.get_value("Supplier", doc.supplier, "tax_id") -%}
      {%- if sgstin_no and not (saddr and saddr.gstin) -%}<p class="muted">PAN: {{ sgstin_no }}</p>{%- endif -%}
    </td>
  </tr>
</table>

{% if doc.project %}
<table class="kv">
  <tr><td class="label">Project</td><td class="value">{{ doc.project }}</td></tr>
</table>
{% endif %}

<h2>Scope of Work</h2>
<table class="kv">
  <tr><td class="label">Title</td><td class="value"><strong>{{ doc.work_title }}</strong></td></tr>
  {% if doc.site_location %}
  <tr><td class="label">Site / Location</td><td class="value">{{ doc.site_location }}</td></tr>
  {% endif %}
</table>

{% if doc.work_description %}
<h3>Detailed Scope</h3>
<div class="scope-detail">{{ doc.work_description }}</div>
{% endif %}

{% if doc.scheduled_start_date or doc.scheduled_completion_date %}
<h2>Schedule</h2>
<table class="kv">
  <tr>
    <td class="label">Scheduled Start</td><td class="value">{{ show_date(doc.scheduled_start_date) }}</td>
  </tr>
  <tr>
    <td class="label">Scheduled Completion</td><td class="value">{{ show_date(doc.scheduled_completion_date) }}</td>
  </tr>
</table>
{% endif %}

<h2>Summary of Work Heads</h2>
<table class="data">
  <thead>
    <tr>
      <th style="width: 6%;">S.No.</th>
      <th>Work Head</th>
      <th class="amt" style="width: 22%;">Amount</th>
    </tr>
  </thead>
  <tbody>
    {% for s in doc.summary_items %}
    <tr>
      <td>{{ loop.index }}</td>
      <td>{{ s.summary_head }}</td>
      <td class="amt">{{ money(s.amount) }}</td>
    </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr class="total-row">
      <td colspan="2">Total Contract Value</td>
      <td class="amt">{{ money(doc.total_amount) }}</td>
    </tr>
  </tfoot>
</table>

<div class="amount-in-words">
  <strong>Amount in words:</strong>
  {{ frappe.utils.money_in_words(doc.total_amount or 0, company_currency) }}
</div>

<div class="annexure-note">
  The detailed Bill of Quantities forming the basis of this Work Order is enclosed as
  <strong>Annexure 1</strong> on subsequent pages and is an integral part of this contract.
</div>

<div class="page-break"></div>

{# ================================================== #}
{# PAGE 2 — TERMS & SIGNATURES                        #}
{# ================================================== #}

<h2>Terms &amp; Conditions</h2>

<h3>Financial Terms</h3>
<table class="data">
  <tr>
    <td style="width: 30%;">Retention per RA Bill</td><td style="width: 20%;">{{ show_pct(doc.retention_percentage) }}</td>
    <td style="width: 30%;">Defect Liability Period</td><td>{{ doc.dlp_months or 0 }} months</td>
  </tr>
  <tr>
    <td>Mobilization Advance</td><td>{{ show_pct(doc.mobilization_advance_pct) }}</td>
    <td>Mobilization Recovery per RA</td><td>{{ show_pct(doc.mobilization_recovery_pct) }}</td>
  </tr>
  <tr>
    <td>Material Advance</td><td>{{ show_pct(doc.material_advance_pct) }}</td>
    <td>Material Recovery per RA</td><td>{{ show_pct(doc.material_recovery_pct) }}</td>
  </tr>
</table>

<h3>Retention Release Schedule</h3>
<table class="data">
  <tr>
    <td style="width: 30%;">Release on Final Bill</td>
    <td style="width: 20%;">{{ show_pct(doc.retention_release_on_final_bill) }}</td>
    <td style="width: 30%;">Release after DLP</td>
    <td>{{ show_pct(doc.retention_release_after_dlp) }}</td>
  </tr>
</table>

<h3>Statutory Deductions</h3>
<table class="data">
  <tr>
    <td style="width: 30%;">Labour Welfare Cess</td>
    <td style="width: 20%;">
      {% if doc.apply_labour_cess %}Applicable @ {{ show_pct(doc.labour_cess_pct) }}{% else %}Not Applicable{% endif %}
    </td>
    <td style="width: 30%;">TDS Category</td>
    <td>{{ doc.tds_category or "—" }}</td>
  </tr>
</table>

{% if doc.payment_terms %}
<h3>Payment Terms</h3>
<div class="scope-detail">{{ doc.payment_terms }}</div>
{% endif %}

<h3>General Conditions</h3>
<ol style="padding-left: 20px; margin: 6px 0;">
  <li>Quantities in the BOQ are estimated; actual measurement at site shall prevail subject to deviation limits per row.</li>
  <li>Any deviation beyond the per-row Deviation Limit % stated in the BOQ requires a written amendment to this Work Order before measurement.</li>
  <li>Retention shall be deducted at the rate stated above from every Running Account Bill and released per the Retention Release Schedule.</li>
  <li>All applicable statutory deductions (TDS, Labour Cess, etc.) shall be made at source per prevailing rates.</li>
  <li>The Contractor is responsible for site safety, statutory compliance, and quality of work as per applicable codes and the Employer's standards.</li>
  <li>Disputes, if any, shall be governed by the jurisdiction of the courts at the Employer's registered office location.</li>
</ol>

<div class="sig-block">
  <table>
    <tr>
      <td>
        <h4>For the EMPLOYER</h4>
        <p>{{ doc.company }}</p>
        <div class="sig-line"></div>
        <p><strong>Authorized Signatory</strong></p>
        <p>Name: ________________________________</p>
        <p>Date: ________________________________</p>
      </td>
      <td>
        <h4>For the CONTRACTOR</h4>
        <p>{{ doc.supplier_name or doc.supplier }}</p>
        <div class="sig-line"></div>
        <p><strong>Authorized Signatory</strong></p>
        <p>Name: ________________________________</p>
        <p>Date: ________________________________</p>
      </td>
    </tr>
  </table>
</div>

<div class="footer-note">
  This Work Order is computer-generated and is valid without signature in digital form.
  When printed, it requires authorized signatures from both parties to be binding.
</div>

<div class="page-break"></div>

{# ================================================== #}
{# ANNEXURE 1 — DETAILED BOQ                          #}
{# ================================================== #}

<h1 style="text-align: center; font-size: 16pt; margin-bottom: 6px;">Annexure 1</h1>
<h2 style="text-align: center; border-bottom: none; margin-top: 0;">Bill of Quantities</h2>
<p class="muted" style="text-align: center; margin-bottom: 12px;">
  Reference: Work Order <strong>{{ doc.name }}</strong> dated {{ show_date(doc.wo_date) }}
</p>

{% if doc.boq_items %}
<table class="data">
  <thead>
    <tr>
      <th style="width: 5%;">S.No.</th>
      <th style="width: 6%;">Item No.</th>
      <th>Description</th>
      <th style="width: 9%;">UOM</th>
      <th class="amt" style="width: 9%;">Qty</th>
      <th class="amt" style="width: 12%;">Rate</th>
      <th class="amt" style="width: 14%;">Amount</th>
    </tr>
  </thead>
  <tbody>
    {%- set ns = namespace(current_head=None, head_subtotal=0, head_index=0, row_counter=0) -%}
    {%- for r in doc.boq_items -%}
      {%- if r.summary_head != ns.current_head -%}
        {%- if ns.current_head is not none -%}
          <tr class="head-subtotal">
            <td colspan="6"><em>Subtotal — {{ ns.current_head }}</em></td>
            <td class="amt">{{ money(ns.head_subtotal) }}</td>
          </tr>
        {%- endif -%}
        {%- set ns.head_index = ns.head_index + 1 -%}
        {%- set ns.current_head = r.summary_head -%}
        {%- set ns.head_subtotal = 0 -%}
        <tr class="head-row">
          <td colspan="7">{{ ns.head_index }}. {{ r.summary_head }}</td>
        </tr>
      {%- endif -%}
      {%- set ns.row_counter = ns.row_counter + 1 -%}
      {%- set ns.head_subtotal = ns.head_subtotal + (r.amount or 0) -%}
      <tr>
        <td>{{ ns.row_counter }}</td>
        <td>{{ r.item_no or "" }}</td>
        <td>{{ r.description or "" }}</td>
        <td>{{ r.uom or "" }}</td>
        <td class="amt">{{ "%.3f"|format(r.estimated_qty or 0) }}</td>
        <td class="amt">{{ money(r.rate) }}</td>
        <td class="amt">{{ money(r.amount) }}</td>
      </tr>
    {%- endfor -%}
    {%- if ns.current_head is not none -%}
      <tr class="head-subtotal">
        <td colspan="6"><em>Subtotal — {{ ns.current_head }}</em></td>
        <td class="amt">{{ money(ns.head_subtotal) }}</td>
      </tr>
    {%- endif -%}
  </tbody>
  <tfoot>
    <tr class="grand-total">
      <td colspan="6">GRAND TOTAL</td>
      <td class="amt">{{ money(doc.total_amount) }}</td>
    </tr>
  </tfoot>
</table>

<div class="amount-in-words">
  <strong>Total in words:</strong>
  {{ frappe.utils.money_in_words(doc.total_amount or 0, company_currency) }}
</div>

<h3>Deviation Limits</h3>
<p class="muted">
  The Deviation Limit % stated alongside each BOQ row controls the maximum cumulative quantity
  that may be billed in Running Account Bills before a Work Order amendment is required.
  An explicit 0% means strict — any qty change requires amendment.
</p>
<table class="data">
  <thead>
    <tr>
      <th style="width: 8%;">Item No.</th>
      <th>Description</th>
      <th class="amt" style="width: 12%;">Estimated Qty</th>
      <th class="amt" style="width: 12%;">Deviation %</th>
      <th class="amt" style="width: 14%;">Max Billable</th>
    </tr>
  </thead>
  <tbody>
    {%- for r in doc.boq_items -%}
      {%- set est = r.estimated_qty or 0 -%}
      {%- set dev = r.deviation_limit_pct if r.deviation_limit_pct is not none else 0 -%}
      {%- set ceiling = est * (1 + dev|float / 100.0) -%}
      <tr>
        <td>{{ r.item_no or "" }}</td>
        <td>{{ (r.description or "")[:80] }}</td>
        <td class="amt">{{ "%.3f"|format(est) }} {{ r.uom or "" }}</td>
        <td class="amt">{{ show_pct(dev) }}</td>
        <td class="amt">{{ "%.3f"|format(ceiling) }} {{ r.uom or "" }}</td>
      </tr>
    {%- endfor -%}
  </tbody>
</table>
{% else %}
<p>No BOQ items defined.</p>
{% endif %}

<div class="footer-note">
  End of Annexure 1 — Work Order {{ doc.name }}.
</div>

</div>{# /.wo-print #}
